        const recipeList = document.getElementById('recipe-list');
        const searchInput = document.getElementById('search-input');
        const formContainer = document.getElementById('form-container');
        const addRecipeBtn = document.getElementById('add-recipe-btn');
        // [/graft:structure]

when.content:
searchInput.addEventListener('input', () => {
    const searchTerm = searchInput.value.toLowerCase();
    recipeBook.recipes = recipeBook.recipes.filter(recipe => recipe.title.toLowerCase().includes(searchTerm));
    updateRecipeList();
});

addRecipeBtn.addEventListener('click', () => {
    const title = document.getElementById('recipe-title').value;
    const ingredients = document.getElementById('recipe-ingredients').value;
    const instructions = document.getElementById('recipe-instructions').value;
    const cookingTime = parseInt(document.getElementById('recipe-cooking-time').value);
    const rating = parseInt(document.getElementById('recipe-rating').value);

    if (title.trim() === '') {
        alert('Recipe title cannot be empty.');
        return;
    }

    recipeBook.recipes.unshift({ title, ingredients, instructions, cookingTime, rating });
    updateRecipeList();
    formContainer.reset();
});

recipeList.addEventListener('click', (event) => {
    if (event.target.classList.contains('view-details-btn')) {
        const card = event.target.closest('.recipe-card');
        const details = card.nextElementSibling;
        if (details) {
            details.classList.toggle('active');
        } else {
            const details = document.createElement('div');
            details.classList.add('recipe-details');
            details.innerHTML = `
                <h3>${card.querySelector('h3').innerText}</h3>
                <p><strong>Ingredients:</strong> ${card.querySelector('p').innerText}</p>
                <p><strong>Instructions:</strong> ${card.querySelector('p').innerText}</p>
                <p><strong>Cooking Time:</strong> ${card.querySelector('p').innerText}</p>
                <p><strong>Rating:</strong> ${card.querySelector('p').innerText}</p>
            `;
            card.appendChild(details);
        }
    }
});

